INSERT INTO `reviews` (`id`, `user_id`, `product_id`, `review`, `rating`, `review_date`, `image`) VALUES
(13, 46, 18, 'Highly Recommended this product!', 5, '2024-12-15 17:23:25', '[\"uploads\\/cargot.jpg\"]'),
(14, 41, 10, 'SUPER GANDA NG TOP I LOVE IT SO MUCH! WILL ORDER NEXT TIME♥️', 5, '2024-12-15 17:30:08', '[\"uploads\\/croptopk.jpg\"]'),
(16, 47, 7, 'I like the design of this dress. Elegant and light to wear. Highly Recommended!', 5, '2024-12-15 17:46:27', '[\"uploads\\/dressc.jpg\"]'),
(17, 34, 7, 'Medyo maluwag lang sa bewang, pero overall, okay naman.', 5, '2024-12-15 17:48:43', '[\"uploads\\/redreviews.png\",\"uploads\\/redreviews1.png\"]'),
(18, 31, 11, 'Ang ganda ng design ng jorts na ito. Stylish at bagay na bagay sa mga casual na outfits. I love how it pairs well with any top.', 5, '2024-12-15 17:52:14', '[\"uploads\\/jortsmoral.jpg\"]'),
(19, 46, 8, 'These pants are super comfy! The length and fit are perfect, not too tight, not too loose.', 5, '2024-12-15 17:53:56', '[\"uploads\\/pantst.jpg\"]'),
(20, 28, 6, 'This shirt is super comfortable! Malambot ang tela at hindi mainit kahit suotin buong araw. Higly Recommended bili na kayo guysss', 5, '2024-12-15 17:57:11', '[\"uploads\\/reviews1.png\",\"uploads\\/reviews2.png\"]'),
(21, 39, 6, 'Perfect ang design ng shirt na ito. Hindi lang maganda ang fit, kundi comfortable din sa katawan. Madali din i-pair sa iba pang damit!', 5, '2024-12-15 17:58:29', '[\"uploads\\/reviews5.png\"]'),
(22, 42, 6, 'Mali yung size na nabili ko pero overall maganda yung shirt', 4, '2024-12-15 18:00:09', '[\"uploads\\/reviews3.png\"]'),
(23, 43, 6, 'Perfect sa pang-araw-araw', 5, '2024-12-15 18:02:02', '[\"uploads\\/reviews4.png\"]'),
(24, 44, 8, 'Medyo mahirap lang i-adjust sa waist ko, pero magaan naman at hindi nakakabitin. Magaan at breathable kaya okay pa rin.', 5, '2024-12-15 18:03:58', '[\"uploads\\/denimreview1.png\"]'),
(25, 30, 12, 'Sobrang stylish at perfect na pang-mall outfit.', 5, '2024-12-15 18:05:38', '[\"uploads\\/dress_review3.png\"]'),
(26, 30, 10, 'Ang tela ng crop top na ito ay magaan at malambot, kaya’t hindi mainit suotin kahit buong araw.', 5, '2024-12-15 18:06:45', '[\"uploads\\/tshirtreview4.png\"]'),
(27, 30, 11, 'Comfortable suotin kahit buong araw. Worth the price!', 5, '2024-12-15 18:07:32', '[\"uploads\\/denimshorts_review1.png\"]'),
(28, 30, 8, 'Definitely worth the purchase!', 5, '2024-12-15 18:09:02', '[\"uploads\\/denimreview3.png\"]'),
(29, 30, 15, 'Best design from STYLEGEN always top quality', 5, '2024-12-15 18:14:30', '[\"uploads\\/bpants.png\"]'),
(30, 28, 17, 'So happy with my purchase! True to size i love the color ????', 5, '2024-12-15 18:16:19', '[\"uploads\\/sshirt.png\"]'),
(31, 28, 20, 'Ang gandaaa naman ng product. What you see is what you get', 4, '2024-12-15 23:56:37', '[\"uploads\\/Screenshot 2024-12-15 181701.png\"]'),
