(1, '680e4e26a32a3', NULL, 'Search Engines Blocked', 'Warning: AIOSEO has detected that you are blocking access to search engines. You can change this in Settings > Reading if this was unintended.', 'error', '[\"all\"]', NULL, 'blog-visibility', '2025-04-27 15:32:54', NULL, 'Fix Now', 'http://localhost/wordpress/wp-admin/options-reading.php', 'Remind Me Later', 'http://action#notification/blog-visibility-reminder', 0, 0, '2025-04-27 15:32:54', '2025-04-27 15:32:54'),
(2, '680e4e26bedf3', NULL, 'Have you connected your site to Google Search Console?', 'AIOSEO can now verify whether your site is correctly verified with Google Search Console and that your sitemaps have been submitted correctly. Connect with Google Search Console now to ensure your content is being added to Google as soon as possible for increased rankings.', 'warning', '[\"all\"]', NULL, 'search-console-site-not-connected', '2025-04-27 15:32:54', NULL, 'Connect to Google Search Console', 'https://route#aioseo-settings&aioseo-scroll=google-search-console-settings&aioseo-highlight=google-search-console-settings:webmaster-tools?activetool=googleSearchConsole', NULL, NULL, 0, 0, '2025-04-27 15:32:54', '2025-04-27 15:32:54'),
