"BobWP and Birgit Pauli-Haack discuss community building for podcasts, emphasizing platform ownership, authentic storytelling, adaptability, engagement, handling challenges gracefully, and celebrating milestones together.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 28 Apr 2025 10:54:06 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:39;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"Do The Woo Community: My Head is Spinning with the Next Big “Ship It”\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"https://dothewoo.io/?post_type=blog&p=95318\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://dothewoo.io/blog/my-head-is-spinning-with-the-next-big-ship-it/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"Morning thoughts buried in something that I cannot share.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 28 Apr 2025 09:06:09 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:40;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:50:\"Do The Woo Community: What Is My Favorite Website?\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"https://dothewoo.io/?post_type=blog&p=95226\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://dothewoo.io/blog/what-is-my-favorite-website/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:179:\"On a lazy Sunday, I pondered my \"favorite website,\" leading to a rabbit hole of indecision, endless projects, and a strong realization: favorites are just too complicated to pick.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 27 Apr 2025 07:55:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:41;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:46:\"Do The Woo Community: Life Without a Computer?\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"https://dothewoo.io/?post_type=blog&p=95175\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:49:\"https://dothewoo.io/blog/life-without-a-computer/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:120:\"Bob reflects on his life before computers, sharing experiences with radio and contemplating a future without technology.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 26 Apr 2025 09:12:49 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:42;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:126:\"Gutenberg Times: WordPress 6.8.1, Tabs and CSS Slider Blocks, Sticky Header, ThemeSwitcherPro and more — Weekend Edition 327\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=40064\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:130:\"https://gutenbergtimes.com/wordpress-6-8-1-tabs-and-css-slider-blocks-sticky-header-themeswitcherpro-and-more-weekend-edition-327/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:20360:\"<p>Hi there, </p>\n\n\n\n<p>With WordPress 6.8 out the door, I start getting deeper into Block themes. What are you working on in the upcoming two months? </p>\n\n\n\n<p>Below you find quite a few videos and podcast episodes for your Weekend entertainment. It&#8217;s hopefully a great mix, and you find something you are interested in. </p>\n\n\n\n\n\n<p>Have a fantastic weekend! </p>\n\n\n\n<p>Yours, <img src=\"https://s.w.org/images/core/emoji/15.1.0/72x72/1f495.png\" alt=\"💕\" class=\"wp-smiley\" /><br /><em>Birgit</em></p>\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-flow wp-block-group-is-layout-flow\">\n<p><strong>Table of Contents</strong></p>\n\n\n\n<ol><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-8-1-tabs-and-css-slider-blocks-sticky-header-themeswitcherpro-and-more-weekend-edition-327/#0-word-press-release-information\">Developing Gutenberg and WordPress</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-8-1-tabs-and-css-slider-blocks-sticky-header-themeswitcherpro-and-more-weekend-edition-327/#0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-8-1-tabs-and-css-slider-blocks-sticky-header-themeswitcherpro-and-more-weekend-edition-327/#2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-8-1-tabs-and-css-slider-blocks-sticky-header-themeswitcherpro-and-more-weekend-edition-327/#3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor</a></li></ol>\n</div></div>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-word-press-release-information\">Developing Gutenberg and WordPress</h2>\n\n\n\n<p>The <a href=\"https://make.wordpress.org/core/2025/04/24/wordpress-6-8-1-release-schedule/\">schedule for WordPress 6.8.1 is out</a>. RC1 is to be ready for testing on April 28, 2025, and the final release two days later on April 30th, 2025. Here are the main issues that will be resolved with this release:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://core.trac.wordpress.org/ticket/63285\">Call to undefined function is_super_admin() in /wp-includes/ms-files.php</a>&nbsp;(This&nbsp;ticket&nbsp;is complete)</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/69923\" target=\"_blank\" rel=\"noreferrer noopener\">Regression in WP 6.8 – Meta boxes area shows unwanted resize handle (&lt;button role=”separator”>) and breaks auto-scroll</a></li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/68139\" target=\"_blank\" rel=\"noreferrer noopener\">Keyboard Shortcuts: Revert delete shortcut to access + z</a></li>\n</ul>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>In his post <a href=\"https://aaron.jorb.in/defining-minor-releases-for-wordpress-6-8-x/\"><strong>Defining Minor Releases for WordPress 6.8.x</strong></a>, <strong>Aaron Jorbin</strong>, WordPress core committer, outlines recommendations for handling minor releases in WordPress 6.8.x, given the move to a yearly major release schedule. He argues that minor releases should be more risk-averse than majors, especially since everyone gets minor updates automatically and WordPress does not maintain multiple older versions. </p>\n\n\n\n<p>Key Points: </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>No new files in minor releases: </strong>Adding new files can break auto-updates for some users and is considered too risky.</li>\n\n\n\n<li><strong>Risk aversion:</strong> Keep changes minimal and package sizes small to reduce update failures.</li>\n\n\n\n<li><strong>New features</strong> are allowed if they are well-tested and not too large, but major changes (like big redesigns) should be avoided.</li>\n\n\n\n<li><strong>Refactors:</strong> Either avoid coding standard refactors or only backport them selectively alongside other necessary changes to avoid unnecessary package bloat.</li>\n\n\n\n<li><strong>Default themes:</strong> Focus on improving existing default themes (e.g., adding new patterns) rather than introducing new ones in minor releases.</li>\n</ul>\n\n\n\n<p><em>Overall, the emphasis is on stability, minimal risk, and maintaining reliable automatic updates for security and maintenance.</em></p>\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p><img src=\"https://s.w.org/images/core/emoji/15.1.0/72x72/1f399.png\" alt=\"🎙\" class=\"wp-smiley\" /> The latest episode <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-117-woocommerce-starter-theme-and-blocks/\">Gutenberg Changelog 117 – WooCommerce Starter Theme and Blocks, WordCamp Europe, and Gutenberg 20.7 and 20.8</a> I sat down with Ellen Bauer, WooCommerce product lead and discussed what she is working on, WordCamp Europe, Create Block Theme, WP-CLI, Gutenberg 20.7 and Gutenberg 20.8 releases. </p>\n\n\n\n<img width=\"652\" height=\"184\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2022/03/Screenshot-2025-05-10-at-12.16.57.png?resize=652%2C184&ssl=1\" alt=\"Ellen Bauer and Birgit Pauli-Haack recording Gutenberg Changelog 117\" class=\"wp-image-40375\" />\n</div></div>\n\n\n\n<p>In this episode of The WordPress Way, <a href=\"https://dothewoo.io/first-time-contributors-and-wordpress-6-8-enhancements-with-birgit-pauli-haack-and-joe-mcgill\"><strong>Exciting Highlights of WordPress 6.8 Release and Community Impact</strong></a>, I&#8217;m thrilled to be joined by my<br />fellow core contributors, <strong>Joe McGill</strong> and <strong>Abha Thakor</strong>, as we celebrate<br />the arrival of WordPress 6.8. As part of this special release show, we<br />dive into the latest and greatest features that make this version truly<br />stand out. From a polished user experience to updates that will benefit<br />content creators, developers, and extenders alike, I&#8217;m excited to share<br />my thoughts on what&#8217;s new and exciting in this latest release.</p>\n\n\n<div width=\"100%\" class=\"wp-block-newsletterglue-showhide ng-block\">\n<div class=\"wp-block-embed__wrapper\">\n<div>    <div></div>    </div>\n</div>\n</div>\n\n\n<h2 class=\"wp-block-heading\" id=\"0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</h2>\n\n\n\n<p><strong>Wes Theron</strong> posted a video explaining <strong><a href=\"https://www.youtube.com/watch?v=62F1bxnqim0\">How to enhance Navigation with a Sticky Header</a></strong>. In this 4-minute video, he walks you through how to create a sticky header and an optional sticky banner using the WordPress Site Editor with a block theme.</p>\n\n\n<div width=\"100%\" class=\"wp-block-newsletterglue-showhide ng-block\">\n<div class=\"wp-block-embed__wrapper\">\n\n</div>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><br />The <a href=\"https://wordpress.org/plugins/easy-tabs-block/\"><strong>Easy Tabs Block</strong></a> plugin arrived from Bangladesh in the WordPress plugin repository. You can use it to build responsive tabbed content in WordPress. &#8220;Designed for both beginners and developers, it integrates seamlessly with the Gutenberg editor while keeping your site fast and clutter-free.&#8221; says the description. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>The <strong>Multidots</strong> team has recently released a plugin designed to enable site owners and administrators to thoroughly analyze the usage of blocks. This plugin, titled <a href=\"https://wordpress.org/plugins/md-governance/\"><strong>MD Governance</strong></a>, empowers WordPress administrators to adjust the access and settings of Gutenberg blocks according to various user roles. This functionality is particularly beneficial for teams, agencies, or site managers seeking to maintain comprehensive control over the editing process within the block editor.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Jamie Marsland</strong> wanted to know: <a href=\"https://www.youtube.com/watch?v=sUizXb7IJ7A\"><strong>Is the WordPress AI Website Builder Any Good?</strong> My Daughter Lily Checks It Out!</a>. You gotta see it! She whipped up the first version of her production company’s website in just 7 1/2 minutes, mostly using what the AI suggested. If you’re curious to give it a shot too, check out the <a href=\"https://wordpress.com/ai-website-builder/\">AI builder link</a> again. Just a heads-up, though—you’re not really the target audience; this builder&#8217;s really meant for folks who aren’t too familiar with WordPress.</p>\n\n\n<div width=\"100%\" class=\"wp-block-newsletterglue-showhide ng-block\">\n<div class=\"wp-block-embed__wrapper\">\n\n</div>\n</div>\n\n\n<p>Currently, there are 1,229 Block Themes in the WordPress Theme Repository. Here are the latest six: </p>\n\n\n\n<div class=\"wp-block-group is-nowrap is-layout-flex wp-container-core-group-is-layout-ad2f72ca wp-block-group-is-layout-flex\">\n<ul class=\"wp-block-list\">\n<li><a href=\"https://wordpress.org/themes/electronics-store-ecommerce/\"><strong>Electronics Store eCommerce</strong></a> by <a href=\"https://superbthemes.com/\">Superb Themes</a> with six Style Variations and 33 Patterns</li>\n\n\n\n<li><a href=\"https://wordpress.org/themes/gutentools-charity/\"><strong>Gutentools Charity</strong></a> by <a href=\"https://themegrove.com/\">Themegrove</a> with four Style Variations and 13 Patterns</li>\n\n\n\n<li><a href=\"https://wordpress.org/themes/divineyoga-fse/\"><strong>Divine Yoga FSE</strong></a> by <a href=\"https://gracethemes.com/\">Grace Themes</a> with seven Patterns</li>\n\n\n\n<li><a href=\"https://wordpress.org/themes/lumivista/\"><strong>Lumivista</strong></a> by <a href=\"https://realtimethemes.com/\">Real Time Themes</a> with eleven Patterns</li>\n\n\n\n<li><a href=\"https://wordpress.org/themes/emerge-business/\"><strong>Emerge Business</strong></a> by <a href=\"https://kantipurthemes.com/\">Kantipur Themes</a> with two Style Variations and ten Patterns</li>\n\n\n\n<li><a href=\"https://wordpress.org/themes/blockskit-accounting/\"><strong>Blockskit Accounting</strong></a> by <a href=\"https://blockskit.com/\">Block Kit</a> with seven Style Variations and ten Patterns</li>\n</ul>\n\n\n\n<img src=\"https://secure.gravatar.com/avatar/ec72cdaef02760dcc902e83f872954cdb34bff4bcbd923a96baaa9ac34e5f205?s=24&d=mm&r=g\" alt=\"realtimethemes Avatar\" />\n</div>\n\n\n\n<a href=\"https://wordpress.org/themes/tags/full-site-editing/\"><img width=\"652\" height=\"392\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/04/Screenshot-2025-04-25-at-17.46.17.png?resize=652%2C392&ssl=1\" alt=\"Screenshot of the latest Block Themes in the WordPress Theme Repository\" class=\"wp-image-40117\" /></a>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</h2>\n\n\n\n<p><strong>Pascal Birchler</strong> explored on <a href=\"https://pascalbirchler.com/css-carousel-block/\"><strong>how to build a CSS Carousel Block for WordPress</strong></a><br />TL;DR: &#8220;it allows for pure CSS-based carousels — no JavaScript required!&#8221; Birchler explains that this project aimed to simplify the process of building carousels on the web by introducing a reusable and modular component. The block allows developers to easily create responsive and interactive<br />carousels with minimal code. </p>\n\n\n\n<p>By using a declarative syntax, users can simply define the content and layout they want to display, eliminating the need for complex JavaScript logic. This approach enables faster development and easier maintenance of carousel components across various websites. The code is available on GitHub: <a href=\"https://github.com/swissspidy/css-carousel-block\">/swissspidy/css-carousel-block</a>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>As mentioned by <strong>JC Palmes</strong> on our <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-116-wordpress-6-8-field-guide/\"><em>116th Gutenberg Changelog episode</em></a>, the team at <em>WebDevStudios</em> was working a process and a plugin that allows agencies to iteratively convert client&#8217;s old WordPress Classic website into a powerful WordPress Block Editor website over time, stretching out your time and budget investment. Within a short amount of time, clients can start producing Block-based content, while your old Classic setup powers the rest of your website. Over time, the old Classic theme would be retired in favor of the Block-based theme. </p>\n\n\n\n<p>The plugin, <strong>ThemeSwitcherPro</strong>, has just been <a href=\"https://themeswitcher.com/introducing-themeswitcher-pro-seamlessly-run-multiple-wordpress-themes-on-a-single-site/\"><strong>released and introduced on the new website for this product.</strong></a> Considering the amount of time it will save you and the fantastic additional service you can offer to our clients, $299 a year is well worth it. They offer a 20% discount for the first 100 customers, and a 30-day money-back guarantee. Brad Williams, co-founder of WebDevStudios, also <a href=\"https://www.youtube.com/watch?v=NIgM5Dzcc_k\">recorded a demo video</a> for you.</p>\n\n\n\n<p><strong>&nbsp;<a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/\" target=\"_blank\" rel=\"noreferrer noopener\">&#8220;Keeping up with Gutenberg &#8211; Index 2025&#8221;</a>&nbsp;</strong><br />A chronological list of the WordPress Make Blog posts from various teams involved in Gutenberg development: Design, Theme Review Team, Core Editor, Core JS, Core CSS, Test, and Meta team from Jan. 2024 on. Updated by yours truly. The previous years are also available: <strong><strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2020/\">2020</a>&nbsp;|&nbsp;<a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2021/\">2021</a></strong>&nbsp;|&nbsp;<strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2022/\">2022</a></strong></strong>&nbsp;|&nbsp;<strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2023\">2023</a></strong> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2024/\"><strong>2024</strong></a></p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor</h2>\n\n\n\n<p>In his video <a href=\"https://www.youtube.com/watch?v=9XcfNpe_H2M&t=1s\"><strong>Custom Domains and HTTPS Support in WordPress Studio</strong></a>, <strong>Nick Diego</strong> teaches you how to set up a custom domain and enable HTTPS (SSL) support in <a href=\"https://developer.wordpress.com/studio/\">WordPress Studio</a> for a more realistic, secure development experience. </p>\n\n\n<div width=\"100%\" class=\"wp-block-newsletterglue-showhide ng-block\">\n<div class=\"wp-block-embed__wrapper\">\n\n</div>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>In episode 166, <strong>Nathan Wrigley</strong> discussed with  <a href=\"https://wptavern.com/podcast/166-ryan-welcher-on-whats-new-for-developers\"><strong>Ryan Welcher on What’s New for Developers</strong></a>. They talked about some of the biggest recent updates to WordPress Core, including the Block Bindings API, Plugin Template Registration API, Preview Options API, and the new Data Views. Welcher breaks down what these new tools are, why they matter, and how they’re making WordPress block development both more powerful and more accessible. &#8220;If you’re interested in what’s new in WordPress development, want to understand where the project is heading, or are curious about the real impact of recent changes and features, this episode is for you.&#8221; wrote Wrigley.</p>\n\n\n<div width=\"100%\" class=\"wp-block-newsletterglue-showhide ng-block\">\n<div class=\"wp-block-embed__wrapper\">\n<div>    <div></div>    </div>\n</div>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>In his livestream, <strong><a href=\"https://www.youtube.com/watch?v=6tflq9LMiZY\" target=\"_blank\" rel=\"noreferrer noopener\">More theme updates for the Block Developer Cookbook site</a></strong>, <strong>Ryan Welcher</strong> focused on completing the user profile system he has been building over the last few sessions.  He dove into some important design changes, tested key functionalities, and troubleshoot live on stream.&nbsp;</p>\n\n\n<div width=\"100%\" class=\"wp-block-newsletterglue-showhide ng-block\">\n<div class=\"wp-block-embed__wrapper\">\n\n</div>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>JuanMa Garrido</strong> explored on how to <strong><a href=\"https://www.youtube.com/watch?v=g0RIwZmD540\" target=\"_blank\" rel=\"noreferrer noopener\">Unit Tests for WordPress blocks</a>.</strong> He wrote some unit tests for the copyright block from the <a href=\"https://developer.wordpress.org/block-editor/getting-started/tutorial/\">&#8220;Tutorial: Build your first block&#8221;</a></p>\n\n\n<div width=\"100%\" class=\"wp-block-newsletterglue-showhide ng-block\">\n<div class=\"wp-block-embed__wrapper\">\n\n</div>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong><a href=\"https://gutenbergtimes.com/need-a-zip-from-master/\">Need a plugin .zip from Gutenberg&#8217;s master branch?</a></strong><br />Gutenberg Times provides daily build for testing and review. </p>\n\n\n\n<p>Now also available via <a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\">WordPress Playground</a>. There is no need for a test site locally or on a server. Have you been using it? <a href=\"mailto:pauli@gutenbergtimes.com\">Email me </a>with your experience</p>\n\n\n\n<p><img alt=\"GitHub all releases\" src=\"https://img.shields.io/github/downloads/bph/gutenberg/total?style=for-the-badge\" /></p>\n\n\n\n<p class=\"has-text-align-center has-small-font-size\"><em>Questions? Suggestions? Ideas? </em><br /><em>Don&#8217;t hesitate to send <a href=\"mailto:pauli@gutenbergtimes.com\">them via email</a> or</em><br /><em> send me a message on WordPress Slack or Twitter @bph</em>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size\">For questions to be answered on the <a href=\"http://gutenbergtimes.com/podcast\">Gutenberg Changelog</a>, <br />send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>Featured Image:</p>\n\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-left\"><strong>Don&#8217;t want to miss the next Weekend Edition? </strong></p>\n\n\n<form class=\"wp-block-newsletterglue-form ngl-form ngl-portrait\" action=\"https://gutenbergtimes.com/feed/\" method=\"post\"><div class=\"ngl-form-container\"><div class=\"ngl-form-field\"><label class=\"ngl-form-label\" for=\"ngl_email\"><br />Type in your Email address to subscribe.</label><div class=\"ngl-form-input\"><input type=\"email\" class=\"ngl-form-input-text\" name=\"ngl_email\" id=\"ngl_email\" /></div></div><button type=\"submit\" class=\"ngl-form-button\">Subscribe</button><p class=\"ngl-form-text\">We hate spam, too, and won&#8217;t give your email address to anyone <br />except Mailchimp to send out our Weekend Edition</p></div><div class=\"ngl-message-overlay\"><div class=\"ngl-message-svg-wrap\"></div><div class=\"ngl-message-overlay-text\">Thanks for subscribing.</div></div><input type=\"hidden\" name=\"ngl_list_id\" id=\"ngl_list_id\" value=\"26f81bd8ae\" /><input type=\"hidden\" name=\"ngl_double_optin\" id=\"ngl_double_optin\" value=\"yes\" /></form>\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 25 Apr 2025 23:45:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:43;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:55:\"Do The Woo Community: Friday Shares, April 25, 2025 v16\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"https://dothewoo.io/?post_type=blog&p=95132\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://dothewoo.io/blog/friday-shares-april-25-2025-v16/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:180:\"Our curated content that is apparently expanding into the Open Web and Tech in general. As we grow this out we are sure you will find something you would have never found yourself.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 25 Apr 2025 10:39:03 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:44;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:42:\"Do The Woo Community: Feeling Out of Place\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"https://dothewoo.io/?post_type=blog&p=95103\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:46:\"https://dothewoo.io/blog/feeling-out-of-place/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"We all have felt out of place, somewhere, sometime. Even repeatedly.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 25 Apr 2025 08:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:45;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:115:\"Do The Woo Community: First-Time Contributors and WordPress 6.8 Enhancements with Birgit Pauli-Haack and Joe McGill\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"https://dothewoo.io/?p=94714\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:114:\"https://dothewoo.io/first-time-contributors-and-wordpress-6-8-enhancements-with-birgit-pauli-haack-and-joe-mcgill/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:311:\"In The WordPress Way episode, host Abha and guests, Birgit and Joe, discuss WordPress 6.8\'s launch, featuring core contributors who highlight improvements for user experience, including design tools, accessibility updates, and performance enhancements, alongside the community\'s impressive contribution efforts.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 24 Apr 2025 09:13:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:46;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"Do The Woo Community: A Plethora of Rock n’ Roll Concerts\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"https://dothewoo.io/?post_type=blog&p=95069\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"https://dothewoo.io/blog/a-plethora-of-rock-n-roll-concerts/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:124:\"Drifting back to my days in the 70\'s when I loved going to concerts ends up challenging myself to remember every band I saw.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 24 Apr 2025 08:53:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:47;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Matt: Reflecting\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=141539\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://ma.tt/2025/04/reflecting/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1632:\"<p>I know there’s been a lot of frustration directed at me specifically. Some of it, I believe, is misplaced—but I also understand where it’s coming from.</p>\n\n\n\n<p>The passing of Pope Francis has deeply impacted me. While I still disagree with the Church on many issues, he was the Pope who broke the mold in so many ways, inspiring me and drawing me back to the Catholic faith I grew up with, with an emphasis on service, compassion, and humility. His passing on Easter Monday, a holiday about rebirth, feels historic. Moments like that invite reflection—not just on personal choices, but on the broader systems we’re a part of.</p>\n\n\n\n<p>My life, which was primarily about generative creative work that was free for everyone to use, has been subsumed by legal battles. From the start, I’ve said this: after many rounds of negotiation that I approached in good faith, WPE chose to sue. In hindsight, those conversations weren’t held in the same spirit, and that’s unfortunate.</p>\n\n\n\n<p>But we can’t rewrite the past. What we can do is decide how we move forward.</p>\n\n\n\n<p>The maker-taker problem, at the heart of what we’ve been wrestling with, doesn’t disappear by avoiding it. If we’re serious about contributing to the future of open source, and about preserving the legacy of what we’ve built together, we need space to reset. That can’t happen under the weight of ongoing litigation. The cards are in WPE hands, a fight they&#8217;ve started and refuse to end.</p>\n\n\n\n<p>So I’m asking for a moment of reflection for us all as stewards of a shared ecosystem. Let’s not lose sight of that.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 24 Apr 2025 03:30:40 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:48;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"WPTavern: #166 – Ryan Welcher on What’s New for Developers\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=195143\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"https://wptavern.com/podcast/166-ryan-welcher-on-whats-new-for-developers\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:59084:\"Transcript<div>\n<p>[00:00:19] Nathan Wrigley: Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p>Jukebox is a podcast which is dedicated to all things WordPress, the people, the events, the plugins, the blocks, the themes, and in this case, what&#8217;s new for developers.</p>\n\n\n\n<p>If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p>If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox and use the form there.</p>\n\n\n\n<p>So on the podcast today we have Ryan Welcher. Ryan is a developer advocate sponsored by Automattic. He focuses on removing barriers to adoption for developers working with Gutenberg and WordPress. He&#8217;s a seasoned WordPress developer, and regular contributor to WordPress and the Gutenberg project. He also streams on Twitch as RyanWelcherCodes, where he focuses on custom block development.</p>\n\n\n\n<p>This interview was recorded at WordCamp Asia 2025 in Manila, where Ryan was giving his Block Developer Cookbook workshop for the second year running. Ryan spends much of his time creating documentation, running live streams, and writing articles, explaining the knots and bolts of new WordPress features for developers.</p>\n\n\n\n<p>He shares his journey from admiring the platform evangelists of the Flash era, to finding his own dream job helping developers understand and implement the new technologies in WordPress.</p>\n\n\n\n<p>We talk about some of the biggest recent updates to WordPress Core, including the Block Bindings API, Plugin Template Registration API, Preview Options API, and the new Data Views. Ryan breaks down what these new tools are, why they matter, and how they&#8217;re making WordPress Block development both more powerful and more accessible.</p>\n\n\n\n<p>He also discusses the growing emphasis on intentional high quality documentation and resources over the past few years, and how many teams are working to make life easier for developers of all skill levels.</p>\n\n\n\n<p>We chat about the balance between the increasing flexibility of WordPress&#8217; UI, and the risk of overwhelming new users, as well as exploring how emerging technologies like AI are shaping the future for WordPress developers and hobbyists alike.</p>\n\n\n\n<p>If you&#8217;re interested in what&#8217;s new in WordPress development, want to understand where the project is heading, or are curious about the real impact of recent changes and features, this episode is for you.</p>\n\n\n\n<p>If you want to find out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p>And so without further delay, I bring you Ryan Welcher.</p>\n\n\n\n<p>I am joined on the podcast by Ryan Welcher. Hello, Ryan?</p>\n\n\n\n<p>[00:03:37] Ryan Welcher: Hello. How are you?</p>\n\n\n\n<p>[00:03:38] Nathan Wrigley: Yeah, I&#8217;m good. Very nice to meet you. This is my second interview in Manila. It&#8217;s WordCamp Asia. You have a presentation coming up. No. You&#8217;ve got a workshop.</p>\n\n\n\n<p>[00:03:47] Ryan Welcher: I do. Yeah. I&#8217;m really excited. It&#8217;s actually the second year in a row that I&#8217;ve given this workshop at WordCamp Asia.</p>\n\n\n\n<p>[00:03:52] Nathan Wrigley: And it&#8217;s a sellout.</p>\n\n\n\n<p>[00:03:54] Ryan Welcher: It is a sellout, yeah. And not in the bad way. It&#8217;s a sellout in the sense that there&#8217;s a wait list apparently and everything. So I&#8217;m very excited. I&#8217;m very flattered and very excited about it.</p>\n\n\n\n<p>[00:04:02] Nathan Wrigley: So before we get stuck into what it is that you are doing here, and that&#8217;s going to be the focus of this conversation around the topic of, well, I&#8217;ll explain that in a moment. Would you just tell us a little bit about who you are, what kind of work you do in the WordPress space and who you work for?</p>\n\n\n\n<p>[00:04:16] Ryan Welcher: Sure. Well, I am a developer advocate. I&#8217;m sponsored by Automattic. I&#8217;ve been with Automattic for, I guess it&#8217;s going to be my third year. Prior to that I was, I used to work at 10up, I&#8217;ve been at a bunch of agencies. I&#8217;ve been using WordPress as a developer since maybe 2009.</p>\n\n\n\n<p>I&#8217;ve been around in this space a while and, yeah, my current role is a lot of fun. I get to do things like this. I get to chat with people in exotic places, and go to conferences and lead workshops and write code that nobody ever has to use in production. It&#8217;s fantastic.</p>\n\n\n\n<p>[00:04:43] Nathan Wrigley: So you&#8217;ve got a really public facing role. Is that the kind of job that you&#8217;ve always wished to do, or is it something that you more or less fell into?</p>\n\n\n\n<p>[00:04:51] Ryan Welcher: If you&#8217;ll indulge me with a bit of an anecdotal story here. When I first started in web work, I used to do a lot of work with Flash. I don&#8217;t know if I&#8217;m aging myself by saying that, but we used to do a lot of work in Flash. And there was this conference called Flash in the Can, and it&#8217;s still around now, it&#8217;s not called that anymore. And there was this guy who used to work for Adobe, his name was Lee Brimlow. I think that&#8217;s how you say it. He was a platform evangelist. His job was literally go to conferences and give really fun, cool talks on the latest, greatest in Flash.</p>\n\n\n\n<p>And I remember seeing this guy, going, this is like my dream job. This is phenomenal. And I just wasn&#8217;t at a place in my career where there was anything like that. And then, fast forward however many years later, and there was an opening for Dev Rel. And I was like, yes, this is exactly what I would love to do.</p>\n\n\n\n<p>I love writing code. I&#8217;ve always enjoyed being a developer, but now this is kind of like, I&#8217;m also pretty outgoing, extroverted, so this kind of fills both. You know, I get to write code and like my dream is just like sitting down writing code with some obscure API, and that&#8217;s literally all, like I just get to tinker, and that&#8217;s what I love about it. It&#8217;s so much fun.</p>\n\n\n\n<p>[00:05:50] Nathan Wrigley: And is that full-time then?</p>\n\n\n\n<p>[00:05:52] Ryan Welcher: It is, yeah. I&#8217;m full-time. Yeah, it is fun. It is very cool. And I realise fully how lucky I am, because this is a fun job and I get to hang out with really cool people all the time. And being public facing is fun, but it&#8217;s, you know, it&#8217;s got its downsides too.</p>\n\n\n\n<p>[00:06:06] Nathan Wrigley: We have this expression in the UK and it&#8217;s called painting the Forth Bridge. And there&#8217;s this bridge in Scotland called the Forth Bridge, and essentially when you&#8217;ve finished painting it from one end, you go to the other end and begin again. And I feel that WordPress, maybe for somebody in your position, is a little bit like that. It&#8217;s this constant treadmill of, okay, that&#8217;s changed. Yeah. Now we need to adapt new content. And yeah, okay, that bit&#8217;s changed over there in the meantime. New content. Is that what it&#8217;s like a bit?</p>\n\n\n\n<p>[00:06:37] Ryan Welcher: A little bit, yeah. I mean it&#8217;s, when we started, there wasn&#8217;t really a Dev Rel team for the open source project that is WordPress. We were like, you know, there&#8217;s a joke, it&#8217;s like, yeah, there&#8217;s five of us or six of us for 43% of the internet. So there&#8217;s like a lot of work to be done, right?</p>\n\n\n\n<p>And so there&#8217;s a lot of that. We are doing a lot of work around documentation and all that sort of stuff, so it&#8217;s like improving that. But every release, there&#8217;s like a new cycle of things that, you know, the new stuff like 6.7, all the block binding stuff and, you know, Interactivity API and all that really cool, fun stuff.</p>\n\n\n\n<p>And we get to do that, but then it&#8217;s like, okay, well then now there&#8217;s new changes to the Interactivity API, so we have to kind of like talk about that a bit and stuff. It&#8217;s always new, but then there&#8217;s always, I love it when we&#8217;re like, hey, remember that bug that people have been talking about for two years? Like, oh, it&#8217;s fixed now. So we get to also be the harbinger of really good news about things like that.</p>\n\n\n\n<p>[00:07:23] Nathan Wrigley: And do you get to put your own roster together of work each week, or does it come in from on high?</p>\n\n\n\n<p>[00:07:28] Ryan Welcher: We kind of, it&#8217;s usually based around the next release. So whatever&#8217;s coming out in the next release, there&#8217;s always sort of like, you know, the featured items that are coming out. So that kind of dictates what we focus on for the next release.</p>\n\n\n\n<p>There&#8217;s no like on high declaration of what we need to work on. It&#8217;s more like we&#8217;re fairly autonomous in what we do, but I mean, it makes the most sense. If there&#8217;s like new features coming with the next version of WordPress, we should probably get that out and, you know, talk to developers and get people testing it and get people working with it, so we can take that feedback, good and bad, and give it back to the teams that are actually working on those features and stuff like that.</p>\n\n\n\n<p>[00:07:59] Nathan Wrigley: So given that it&#8217;s a Dev Rel job, developer relations, is that your target audience? It&#8217;s definitely developers, a hundred percent developers, not novices?</p>\n\n\n\n<p>It could be a 101 article on how to use WordPress or, you know, a video piece of content or something like that. Right up to, okay, here&#8217;s the nuts and the bolts of exactly how this thing works.</p>\n\n\n\n<p>[00:08:22] Ryan Welcher: Yeah, exactly. Like, I did an article on the developer blog, developer.wordpress.org/news. It was on like the internals of webpack, which is like, if you&#8217;ve ever messed with webpack, nobody ever wants to deal with internals of webpack, but WordPress handles it. It does this really elegant thing where you don&#8217;t have to actually install packages that WordPress provides. It kind of like all of a sudden just uses the ones that are coming, that are with the install.</p>\n\n\n\n<p>So like explaining all that, it&#8217;s cool, I get to nerd out and get right into the details but, you know, it&#8217;s not for everyone. Yeah, but then we&#8217;re like, I&#8217;ve also written our articles on like an introduction to SlotFill or an introduction to Block Variation so, yeah.</p>\n\n\n\n<p>[00:08:55] Nathan Wrigley: It feels like, if we were to rewind the clock like three or four years, there wasn&#8217;t so much emphasis put on documentation, knowledge base articles, video content, learn.wordpress.org. But it feels like in the last two or three years, a much greater emphasis has been put on getting the pieces of documentation right. Getting the Learn resources, you know, putting the courses together and those kind of things. Just looking at it from the outside, that&#8217;s what I think. But is this on the internal side, is this what&#8217;s happening?</p>\n\n\n\n<p>[00:09:22] Ryan Welcher: Yeah, there&#8217;s definitely a focus on that. I mean, when you&#8217;re a developer and you don&#8217;t have the resources to get the answers that you&#8217;re looking for, that&#8217;s extremely frustrating. We&#8217;ve always had documentation, we&#8217;ve had, you know, it&#8217;s like 20-year-old documentation. It&#8217;s been around a long time.</p>\n\n\n\n<p>But we&#8217;ve spent a lot of time improving that. Like, we&#8217;ve focused a lot on the Block Editor Handbook because block development is something that can be very difficult, especially if you&#8217;re coming from, you know, solely a PHP background, and you&#8217;re not really up to speed on React or you just don&#8217;t know JavaScript as deeply as other folks do.</p>\n\n\n\n<p>And I mean, our job is to like make that transition easier, as much as possible, right? So that&#8217;s why there&#8217;s a lot of tooling around it that abstracts away the things, like the scripts package, which is like the build process that the Gutenberg plugin uses it, but it&#8217;s also like the defacto build process for building blocks.</p>\n\n\n\n<p>That handles all that webpack stuff, that handles all that config stuff. You just have to like build your files. Like, you don&#8217;t have to worry about that. So there&#8217;s a lot of trying to make life easier, simpler. And a lot of that is in improvements to documentation, but there&#8217;s also like quality of life fixes for people who are working in the code specifically.</p>\n\n\n\n<p>You know, like I spent a lot of time working, like the Create Block package is like my baby. I absolutely love it. It&#8217;s not my baby, like I didn&#8217;t build it, I&#8217;ve just been trying to maintain it as much as I can and adding new features to make life a little bit easier so you can like reuse it and, I don&#8217;t know, I could get into the minute details.</p>\n\n\n\n<p>But I love that kind of stuff because as a developer, having been one for a long time, I know what I like and I think, I&#8217;m not saying like, what I like everyone should like, but I know when something is getting in my way versus helping me. And I think that&#8217;s a really, that&#8217;s kind of like my compass that I try to work with. It&#8217;s like, okay, it&#8217;s great, but it&#8217;s done all these things I don&#8217;t need, now I have to go and delete all that and figure out all this other stuff to get around this scaffold and, I don&#8217;t know, I&#8217;m really in the weeds right now.</p>\n\n\n\n<p>[00:11:04] Nathan Wrigley: Yeah, yeah. But it feels like, I&#8217;m kind of asking the same question again really, about the materials being created in a much more, well, intentional way. Yeah, the backstory to that, presumably though, is that there&#8217;s more boots on the ground. And I don&#8217;t know if it&#8217;s, in your case, it&#8217;s Automattic sponsoring you into the project. Is there more focus on that from, well, let&#8217;s just go from the Auttomatic side, so more investment from them, yeah?</p>\n\n\n\n<p>And if that&#8217;s the case, is that a reaction to anything? Like, perhaps the rise of SaaS platforms, proprietary platforms, you know, the Wixs and the Squarespaces. Because that&#8217;s interesting. It kind of feels like that&#8217;s always been talked about, you know, WordPress versus all the other platforms. Pay your $20 over there per month, and you get this, and you get access to their platform and it&#8217;s well documented and so on. So I didn&#8217;t know if it was connected to that.</p>\n\n\n\n<p>[00:11:57] Ryan Welcher: I don&#8217;t think there was any, I think that the rise of Dev Rel played a large part in that. Like, I don&#8217;t know the reasoning behind the creation of the team, that was decided before I joined. But I think that in the past four and five years, there&#8217;s been a real, like just across the tech community, there&#8217;s been a real like surge in the concept of developer relations and improving developer experience.</p>\n\n\n\n<p>Because I think people realise that developers, like a lot of these platforms, developers are literally their client base, right? And so I think Automattic recognised that and thought, hey, it&#8217;d be great if we had a dedicated team of folks that were just making life easier for developers. You know, I always say that there&#8217;s no, like I have no KPIs or whatever, I just make things, my mandate is to make things better, as much as possible.</p>\n\n\n\n<p>[00:12:40] Nathan Wrigley: Where do you make things? So is it things like YouTube videos, written documentation, knowledge base articles, blog posts?</p>\n\n\n\n<p>[00:12:48] Ryan Welcher: A bit of everything. I tend to focus a bit more on the, like I have a live stream that I do on Twitch every Thursday at 10:30 Eastern. I tend to do a lot more of that sort of stuff. That&#8217;s kind of like more my wheelhouse. I write articles. I&#8217;m not the best writer. I rely on ChatGPT to help me clean that up a little bit. I write the articles, but then I, you know, smarter brains than I help me make it nicer to read.</p>\n\n\n\n<p>Yeah, so I think we all, like everyone across our team has their own sort of strengths and we all kind of like play to our strengths a bit. Mine is definitely more like in the video side. I try to use my development experience as much as possible to do more complicated things. That&#8217;s not to say that the other folks on our team don&#8217;t either, but, I mean, I think I&#8217;m in a position to be able to be like, here&#8217;s a really complicated issue that people are having and how would we solve that? And it&#8217;s fun because I get paid to solve that. And other people who have clients that don&#8217;t want to pay them 20 hours just to fart around on a problem is, that&#8217;s where I can come in and help with that.</p>\n\n\n\n<p>[00:13:39] Nathan Wrigley: Give that to us again though. Where do you do your YouTube stuff? And what handle would that be?</p>\n\n\n\n<p>[00:13:44] Ryan Welcher: I stream on Twitch and YouTube. I multistream to both platforms. Thursdays, 10:30 Eastern, every week.</p>\n\n\n\n<p>[00:13:50] Nathan Wrigley: And what handle would that be?</p>\n\n\n\n<p>[00:13:52] Ryan Welcher: Ryan Welcher Codes.</p>\n\n\n\n<p>[00:13:53] Nathan Wrigley: We&#8217;ll drop all of the links that we stumble across during this episode into the show notes. Yeah, so you can find it all there.</p>\n\n\n\n<p>So WordCamp Asia, the workshop that you are giving is called the Block Developer Cookbook. And I am just going to read the blurb so that you, dear listener, get some idea of what it is that Ryan&#8217;s doing. And it says, this is the second year for the Block Developer Cookbook Workshop at WordCamp Asia. Last year in Taipei, we covered lots of topics like block transforms, adding editorial notes, creating a custom format and more.</p>\n\n\n\n<p>This year, in addition to the existing recipes from the last year, we will have new ones to choose from that leverage the newest features released in WordPress 6.7, such as Block Bindings API, Plugin Template Registration API, Preview Options API and more. And there&#8217;ll be a workshop all about that.</p>\n\n\n\n<p>And so I think your intention at this workshop, should the internet hold up, is to do like an interactive thing where the audience say, I want to do this, and you hopefully help them out with that because that&#8217;s very brave.</p>\n\n\n\n<p>[00:14:58] Ryan Welcher: You can say that, yeah. I&#8217;ve had this idea for a while of a workshop where the attendees pick the content. Because, especially with a topic like block development, it&#8217;s like saying, come to my WordPress workshop. Like, there&#8217;s so many things, right? So like picking something for everyone is really hard.</p>\n\n\n\n<p>And so I thought, well you know what? I&#8217;ll build this little website and they can go in. It&#8217;s like chef theme because it&#8217;s block developer cookbooks. So, you know, you login, you have a little chef hat on your avatar and stuff like that. But you can vote on which of the recipes that you&#8217;d like to work on. And so that&#8217;s the idea. And then they vote and then we go from top to bottom. We get as many done as we can in the 90 minutes or whatever it is.</p>\n\n\n\n<p>I&#8217;ve been going to conferences and speaking at conferences long enough to know better than to rely on the wifi, but I thought, I&#8217;m just going to do it. So this is the second year in a row. I did this last year as well at Taipei. So I&#8217;m like super flattered that they accepted my submission is a second time in a row, so.</p>\n\n\n\n<p>[00:15:49] Nathan Wrigley: I think there&#8217;s a push to make WordCamps a little bit more, and I&#8217;m going to use air quotes, exciting, interactive. Yeah, it seems like, you know, Jamie Marsland&#8217;s, the thing that he does with the Speed Builds, just sort of grabbing the attention of the audience a bit more. Does it feel a bit like that?</p>\n\n\n\n<p>And workshops, they seem to grab the audience a little bit more, because it&#8217;s more interactive. It&#8217;s kind of less being presented to and more interacting with. So I don&#8217;t know, kind of opening up the laptop, trying things out. What do you think? Is that a way that you think events should go in the future?</p>\n\n\n\n<p>[00:16:23] Ryan Welcher: I think so too. I think for me personally, I gravitate towards workshops more than talks. I&#8217;ve given talks and I&#8217;ve done workshops before and I think I enjoy, personally enjoy the workshop aspect because there&#8217;s a lot more like interaction and back and forth. And like if you have a question, you just raise your hand and we answer, you know. And it&#8217;s just more organic, I guess is maybe how I&#8217;d describe it.</p>\n\n\n\n<p>But, yeah, I think you&#8217;re right. These sort of like fun interactive things. I have some 3D printed swag that I&#8217;m bringing. I don&#8217;t have nearly enough, so I&#8217;m going to have to come up with a, maybe whoever asks a question gets a, it&#8217;s a little like key chain of like a chef hat with the WordCamp 2025 on it.</p>\n\n\n\n<p>[00:16:57] Nathan Wrigley: I am sure it&#8217;ll come out on WordPress TV at some point in the near future. But yeah, good luck with that at least anyway.</p>\n\n\n\n<p>But some of the bits and pieces that you are going to be talking about, we&#8217;re going to get into that now. And the way I want to take this interview is we&#8217;re at WordPress 6.7 at this point. It depends really on when you&#8217;re listening to this, but we&#8217;re at that point at the moment.</p>\n\n\n\n<p>There&#8217;s a whole bunch of stuff that has dropped, and I feel that the audience for this podcast, there&#8217;s a ton of developers. But there&#8217;s also lots of people who are not really inside the ecosystem too much. You know, just regular users. Maybe they&#8217;re using a page builder, maybe they&#8217;re a freelancer, something like that, and they don&#8217;t follow the project, they don&#8217;t really obsess about it as much as I do, and probably as you do as well.</p>\n\n\n\n<p>So let&#8217;s just take a couple of these and discuss them. And if we could go in at a low level. So we&#8217;re not able to do a video and open a code editor on this podcast, it&#8217;s all about the audio, but let&#8217;s start talking about the Block Bindings API. What does it do?</p>\n\n\n\n<p>[00:17:56] Ryan Welcher: Oh, I love the Block Bindings API. So there has been a long standing need in WordPress to be able to connect custom meta or custom fields with displaying them basically. And so, in classic themes, we would always just have a meta box that you would put some stuff in, and then in your templates you would just pull that information out of the database and show it.</p>\n\n\n\n<p>With block themes, it&#8217;s a little bit different because we don&#8217;t really have, you can do that in some places, anyways. The idea behind Block Bindings is that you can connect a block with a piece of post meta, or a custom field and have it display. So you take a paragraph block, let&#8217;s use the example of like a personnel list maybe.</p>\n\n\n\n<p>And so you&#8217;ve got like job description, you&#8217;ve got the date hired, all these pieces of metadata. And so what you can do with the Block Bindings API is you can connect that to say a paragraph block. So you can insert just a regular old paragraph block and then in the UI you can go over and say, okay, I want to connect the content field of that paragraph block with this piece of post meta. And it just shows up in there.</p>\n\n\n\n<p>And then you can actually edit it in the block editor, as opposed to having to open up like the custom fields panel down at the bottom. You can edit it and it goes both ways. And it&#8217;s like extremely powerful. It&#8217;s the beginning of how powerful it&#8217;s going to get, but currently it supports, there&#8217;s four blocks that are supported. There&#8217;s the paragraph block, header block, the image block, and the button block.</p>\n\n\n\n<p>So you have to use one of those four blocks, unless you want to get into custom bindings, which is sort of the second piece of it, which is like a means of defining your own binding sources. And then you can connect those binding sources to a block as well.</p>\n\n\n\n<p>So if you wanted to connect to any sort of custom field manager plugin that&#8217;s out there, you could write your own that connects to that, and then you can have the block just read from that and it&#8217;s inline. You get a visual representation of it. It&#8217;s really, really cool.</p>\n\n\n\n<p>[00:19:41] Nathan Wrigley: So it&#8217;s the kind of thing that in the past you would probably have got a plugin to do. Something like, I don&#8217;t know, maybe you would&#8217;ve downloaded Pods or something like that to do that.</p>\n\n\n\n<p>[00:19:50] Ryan Welcher: I mean, it doesn&#8217;t manage the custom fields for you. So some of those plugins do that very, very well. But what it does do is it connects the block editor with that meta, which has been the missing piece for a while. It&#8217;s still kind of in its infancy, but already it&#8217;s shown to be super powerful.</p>\n\n\n\n<p>Like, now we&#8217;re seeing a lot of people who are not writing custom blocks for this anymore. Like, it used to be like, okay, I want to show the job description, so I have to write a custom block that introduces something in the sidebar where you input the meta there and then that block displays that because you&#8217;re handling that, it&#8217;s a dynamic block, you&#8217;re pulling the meta out and the PHP, all that sort of stuff.</p>\n\n\n\n<p>Now you don&#8217;t have to do that. Now you can just do a block variation of a paragraph block to auto set the meta that you want. You don&#8217;t even have to do that. You can do it right in the admin. But I would recommend doing a block variation, because setting that up every single time is a bit tedious. And especially if you&#8217;re doing it for clients, you can just do a block variation that says like, job description, and then you click on it and it just goes in.</p>\n\n\n\n<p>[00:20:46] Nathan Wrigley: So you, your face, gave away something a moment ago. And it sounds like you are quite excited about what&#8217;s coming and is not yet there. But I guess one of the nice things about your job is that you really have that high level view of what&#8217;s going on in the project. And you can imagine scenarios in the near term, maybe 6.8 or something like that. For example, in this case, the Block Bindings API will enable novice users to do, well, more than you&#8217;ve just described. Yeah, that&#8217;s kind of a nice position to be in.</p>\n\n\n\n<p>[00:21:13] Ryan Welcher: I don&#8217;t have, I will say this for the record, I don&#8217;t have an inside track to anything that&#8217;s not available on like Make. But I know some of the folks that are working on it, and like just in conversation, I&#8217;m very excited. I can see where it&#8217;s going, and that&#8217;s not because I have inside information, it&#8217;s just because the logical next step, it looks really cool.</p>\n\n\n\n<p>Like, more blocks. Being able to do it with custom blocks will be huge once you have a custom block that you can now connect it to meta and stuff like that. There are some technical hurdles that need to be addressed to do that, but it&#8217;s going to be a big, I hate using the word game changer, but it&#8217;s going to be a game changer.</p>\n\n\n\n<p>[00:21:47] Nathan Wrigley: One of the things which I always find interesting when I speak to people who are really in the weeds of it all, is that the stuff just, well, it just keeps on coming out. Because you are in there every day and it&#8217;s so self-evident to you. You know, you use all these acronyms, you know where everything connects, and you know how to make everything work. How do you feel like that is project wide?</p>\n\n\n\n<p>We&#8217;re sort of going off piste a little bit here, but we&#8217;ll come back to your presentation, your workshop in a minute. How straightforward is it for people to keep up to date with this, and where would you point them? If somebody was really wanting to find out, for example, about the Block Bindings API, where&#8217;s the best place?</p>\n\n\n\n<p>And I think what I&#8217;m trying to say is, there&#8217;s so much coming that it&#8217;s hard to keep up, for somebody that it isn&#8217;t paid to do it like you are. Is the documentation easy to find? There&#8217;s not really a question in there, but it&#8217;s just a, well, everything&#8217;s just coming so quickly, so fast, and it&#8217;s so disparate and you&#8217;ve got to spend, you know, like a whole week trying to track everything down and map everything to everything else.</p>\n\n\n\n<p>[00:22:48] Ryan Welcher: I would say start with, it is a bit like drinking from the fire hose for sure. Like, there&#8217;s a lot of information. You&#8217;ve got stuff on the make.wordpress.org. where they sort of talk about what&#8217;s coming. You&#8217;ve got the Gutenberg releases. Like the Gutenberg, it&#8217;s on a two week release cycle, so there&#8217;s constant things coming out.</p>\n\n\n\n<p>So one really great way of keeping up with that is there&#8217;s a, what&#8217;s new in Gutenberg post that comes out every two weeks, that talks about high level features. And then it&#8217;s got like a change log of everything that was merged in those two weeks. So that&#8217;s a really great way to like see what&#8217;s coming at a higher level, but also really get in the weeds.</p>\n\n\n\n<p>Like, you can say, okay, this bug that I know about, oh look, they fixed it or whatever. That&#8217;s a really great place to start. You can hang out in the WordPress Slack where they do the Core Editor meetings, the Block Editor meetings, and sort of like ask questions in the open floor or just see what people are talking about.</p>\n\n\n\n<p>Depending on what you&#8217;re trying to do, the GitHub repo is kind of an okay place to get some information. You&#8217;re going to get a lot of information, but that would be a place. I mean, it&#8217;s, I do it full time and it&#8217;s hard, so I get it. But the reason, that&#8217;s why I exist because if I can compile this stuff and make it palatable and easy to find for others, that&#8217;s what Dev Rel is, right? Like that&#8217;s what a lot of what we do is.</p>\n\n\n\n<p>So like I&#8217;ll spend the time messing around with the Block Bindings API, and then I&#8217;ll do a live stream on it, where I&#8217;m like, okay, so we&#8217;re going to do this, and this is why I did it this way, and this is why you should do it this way because it&#8217;s easier, you know? And so like I can do all that busy work to help others who don&#8217;t, you know, because ain&#8217;t nobody got time to do all that, right? You know what I mean? So.</p>\n\n\n\n<p>[00:24:15] Nathan Wrigley: Yeah, that&#8217;s kind of a nice summation of where I was trying to get to. So let&#8217;s move on.</p>\n\n\n\n<p>Another thing which is going to be mentioned, well, who knows whether it&#8217;ll come up, maybe somebody will ask about it. But the questions basically the same. What is the Plugin Template Registration API? What would that be and why would you want to use it?</p>\n\n\n\n<p>[00:24:32] Ryan Welcher: So the example that I have is that you&#8217;ve registered a custom post type that manages people. This is going to be a common theme throughout this. And you want to inject a single page template for that particular post type that&#8217;s curated, that isn&#8217;t part of the theme that&#8217;s being shipped.</p>\n\n\n\n<p>So it allows you to add templates to the active theme from a plugin, from a WordPress plugin. Which is really, really, really handy. Because if you have a plugin that, you know, you have a jobs list plugin, you probably want to provide some default templates so you can just display all the custom fields and everything, and the person that&#8217;s installed your plugin just gets that.</p>\n\n\n\n<p>They can just go to the single page for each job and they have a default template. It&#8217;s a fairly straight, it&#8217;s like one hook, or a filter, I think. So it&#8217;s fairly straightforward, but it&#8217;s super powerful, it&#8217;s like a quality of life thing.</p>\n\n\n\n<p>[00:25:16] Nathan Wrigley: I wondered if it was something that developers had been clamoring for.</p>\n\n\n\n<p>[00:25:20] Ryan Welcher: I can remember like a year and a half ago spending half an afternoon figuring out, how can I do this? And it&#8217;s possible but, wow, is it ever in the weeds? So now it&#8217;s not. Now it&#8217;s like a filter that you just tell it where your template is and it shows up in your templates list.</p>\n\n\n\n<p>[00:25:33] Nathan Wrigley: Once again, we&#8217;ll put the links into the show notes. Okay, next one. Alright, Preview Options API.</p>\n\n\n\n<p>[00:25:41] Ryan Welcher: That&#8217;s a really big, fancy title for a new slot, for a slot fill. So in the preview panel where you can preview it as like a, you know, on mobile, desktop and tablet, there&#8217;s a slot that you can put something in there, and that&#8217;s kind of what it&#8217;s. So you can do whatever you want with it.</p>\n\n\n\n<p>I&#8217;ve seen an example where people were toggling light and dark mode. You could have it, I mean, whatever you can imagine, you can put it in there because it&#8217;s a, like a slot is sort of like a hook, like an action.</p>\n\n\n\n<p>[00:26:04] Nathan Wrigley: Yeah, nice and straightforward. This one for me is probably the most interesting one. I don&#8217;t know why, I just find myself drawn to this one. And it&#8217;s not an API, we&#8217;re talking about data views. What is that?</p>\n\n\n\n<p>[00:26:16] Ryan Welcher: The data views is wildly powerful. It&#8217;s a component, a component in the sense of like a JavaScript component. It&#8217;s what powers a lot of the views that you get in the site editors. So if you go into like your templates, or your pages was the first one, you can see it in a grid view, you can see it in a list view.</p>\n\n\n\n<p>I believe the intention is that, as the site editor sort of spreads into other parts, you&#8217;ll see it being used for things like the post list view and stuff like that. So it&#8217;s a super powerful component. It&#8217;s being used in Gutenberg. I believe it&#8217;s still technically experimental because they&#8217;re still working on it.</p>\n\n\n\n<p>[00:26:48] Nathan Wrigley: Feels like a nice one, that one, not just for developers who are building websites, but also for clients themselves, because they can suddenly, I don&#8217;t know, you&#8217;re selling houses, real estate websites, something like that, and suddenly you&#8217;ve got this house, custom post type, something like that. And there&#8217;s this image and there&#8217;s a number of bedrooms and you can make it sortable and filterable. We want to drill into the houses that are between 150,000 and 300,000. We want to reverse the order, that kind of thing.</p>\n\n\n\n<p>And the end user, the real estate agent will be able to do that. And so it&#8217;s going to make the whole project easier to understand, easier to maintain. So custom post types, pages, posts, users, that&#8217;s my understanding anyway. Is that done through a UI? Is that going to be done through a UI, or is that going to be something like opening up templates?</p>\n\n\n\n<p>[00:27:37] Ryan Welcher: It&#8217;s a React component that you will provide the information. So right now it&#8217;s a little lower level I think, than they maybe want it to be because there&#8217;s a lot, I&#8217;m kind of just going off what I think rather than, like no one&#8217;s told me this. But having used it a little bit, there is definitely some API refinement that could be done, in the sense of like being able, because you have to provide literally everything for it to handle all of the actions for like sorting and all that stuff. And I think what they&#8217;re trying to do is make it a little bit easier to use. So you just give it data, as opposed to like having to define all the callbacks when you click a specific button and stuff like that.</p>\n\n\n\n<p>[00:28:09] Nathan Wrigley: It&#8217;ll certainly make the UI, the admin area more, I don&#8217;t know, more feature rich. Hopefully this will bring it more into parity with all of those other platforms out there.</p>\n\n\n\n<p>Have you, and again, this is not really something that you are talking about, but this was just something that occurred to me. The biggest visual change that I saw in WordPress 6.7 was zoom out, zoom out mode.</p>\n\n\n\n<p>Yeah, I just think the first time I, okay, I&#8217;ll explain. So let&#8217;s say you drop a pattern into a post or a page or something like that. Suddenly the whole thing kind of just zooms away. The page, the pattern is somehow distant. Everything shrinks almost like a mobile view, and it kind of just happens without you invoking it. And so that&#8217;s what that is, I think. What&#8217;s the point of that?</p>\n\n\n\n<p>[00:28:55] Ryan Welcher: So you could get a sense of what you&#8217;ve just inserted in the overall size of the content. So like, if you&#8217;re writing really long pieces, my workshop website, I have very long content because it&#8217;s like a step-by-step, huge code blocks. For me to be able to insert something and get a sense of where it is on the page and look at it, that&#8217;s kind of what that&#8217;s for.</p>\n\n\n\n<p>[00:29:11] Nathan Wrigley: I have a fairly small laptop, and by the time that the left sidebar and the right sidebar and the block editor have all gone in there, by the time I&#8217;ve dropped a pattern in, there&#8217;s basically no real estate left on the screen for me to see what&#8217;s above it or below it. And this pulls it right out and gives you the impression of, well, there&#8217;s the whole blog post.</p>\n\n\n\n<p>And although that sounds really trivial, if the branding and everything really matters and you want one thing to follow another, I don&#8217;t know, it&#8217;s a landing page or something like that. It just gives you that overview and you can obviously move things around. Yeah, it&#8217;s hard to describe how profound it is. But it makes that editing experience, especially for novices, just so much more straightforward.</p>\n\n\n\n<p>[00:29:50] Ryan Welcher: Oh, for sure, like, and if you drop a complicated pattern in the wrong spot, you&#8217;ll see that immediately. So yeah, it&#8217;s like a, I keep using the phrase quality of life, but it really is like a, oh, that&#8217;s just a nice touch. It&#8217;s made your life a little easier. And that&#8217;s kind of like, you know, I know there&#8217;s a lot of refinements going into the UI to make the writing experience better and easier, so yeah.</p>\n\n\n\n<p>[00:30:07] Nathan Wrigley: A little bit off piste, and I&#8217;m putting you on the spot here. If you had to pick one thing that&#8217;s coming that people may not know about, I mean, it doesn&#8217;t have to be something revolutionary, but just something that you are curious about that is going to drop soon. I don&#8217;t know, the next 6 or 12 months, something like that, that you think people will get something out of and enjoy and be excited about. I know that&#8217;s putting you on the spot.</p>\n\n\n\n<p>[00:30:31] Ryan Welcher: I don&#8217;t have one thing per se. I&#8217;m super excited about the concept of bits. It&#8217;s a very complicated thing, but being able to define areas that you can edit in the editor. So for example, the example that probably makes the most sense without me showing, like using my hands because nobody can see me, is like when you have a block binding that is connected to a piece of post meta. That&#8217;s it. Let&#8217;s use the, whatever the byline aspect, you know? So it&#8217;s like a bio or something that&#8217;s connected in post meta.</p>\n\n\n\n<p>If you just want to edit one part of it, you can&#8217;t. You could edit the whole field, but you can&#8217;t edit just one section of it. Or if you have something like, my block developer cookbook site&#8217;s got a cooking time block that says, it&#8217;s got a little like cooking timer icon, and then it&#8217;s got 10, and then it says minutes.</p>\n\n\n\n<p>And, well, the 10 part is actually the post meta. But I can&#8217;t edit that in line in the block editor because the whole output is, it&#8217;s like a span tag with some stuff, right? And so what bits would allow me to do is delineate that, I want to be able to edit just the 10, just that number. And that&#8217;ll be super, super powerful. It&#8217;s like an editable area inside of a larger editable area.</p>\n\n\n\n<p>[00:31:32] Nathan Wrigley: Oh yeah. And I can see that being powerful in a whole bunch of different ways. Yeah, that&#8217;s interesting.</p>\n\n\n\n<p>[00:31:37] Ryan Welcher: Yes. Yeah. And there&#8217;s obviously the Interactivity API, obviously, but it is one of the most exciting things that I&#8217;ve, I mean, it&#8217;s already out and there&#8217;s just more stuff coming and they&#8217;re just doing really, really cool things. I just love it. It is so cool.</p>\n\n\n\n<p>[00:31:50] Nathan Wrigley: Do you think, again, just kind of dropping you into it a little bit, do you think we&#8217;re at any risk of overcomplicating the amount of things that you can do in WordPress at the minute? Here&#8217;s an example. Let&#8217;s say I just took somebody off the street and said, here&#8217;s a brand new installed WordPress website. It allows you to make content, publish websites, off you go.</p>\n\n\n\n<p>How realistic do you think it is with all the different bits and pieces that are dropping? I know you don&#8217;t have to get into the weeds of all this, but how easy do you think the UI is right now? Do you think it&#8217;s getting more complicated at the expense of, my question basically boils down to, are there too many options right now in the same UI, which make it difficult for people to understand who are new to the project?</p>\n\n\n\n<p>[00:32:30] Ryan Welcher: That&#8217;s an interesting question. WordPress has had a philosophy of decisions, not options for a long time. And I think Gutenberg is providing more options now, which is good.</p>\n\n\n\n<p>So like, if I were to take my mother who&#8217;s not technical at all and sit her down and say, build a website, she would probably have a better chance of doing it with Gutenberg than she would&#8217;ve pre 5.0, because she can control every part of it. I mean, I&#8217;d have to tell her how to do it all because she&#8217;s not technical.</p>\n\n\n\n<p>But I think that there is a lot of options, but there&#8217;s also a lot of potential for creativity. And you have access to almost everything that you would need in the editor experience now, whereas you didn&#8217;t before. If you wanted to build a very customised theme, like in classic, and this isn&#8217;t like taking a shot at classic, but if you wanted to have a person post type, you couldn&#8217;t do that. You needed to edit code to be able to output that meta.</p>\n\n\n\n<p>I mean, I&#8217;m sure there were plugins and stuff, but now you don&#8217;t really need to do that. You have everything that you need as long as you know where to click to find it. But it&#8217;s like, anybody who&#8217;s never used WordPress would have to figure that out in any platform. You&#8217;d have to sort that out. I mean, there&#8217;s a lot of options, which can be confusing, but now you can do whatever you want to do, for the most part.</p>\n\n\n\n<p>[00:33:38] Nathan Wrigley: I think it&#8217;s curious because for the longest time people have been sort of saying, you know, the sky&#8217;s falling in, the job market for WordPress developers is just going to get hollowed out because the UI, you know, the ability to do things, a novice being able to do things, it&#8217;s difficult. We should make it more straightforward. There&#8217;s going to be no left work for, I don&#8217;t know, freelancers, implementers, that kind of thing.</p>\n\n\n\n<p>I don&#8217;t think that&#8217;s the case. I think all of these options are getting put in and some of the things that we talked about, you know, the Interactivity API and all of that, that&#8217;s the technical stuff. So there&#8217;s all of these new possibilities that are getting created, but it&#8217;s not going to be, it&#8217;s not probably going to be in the boundaries, at the beginning anyway, of a complete novice.</p>\n\n\n\n<p>So it&#8217;s creating new workflows for developers to push what&#8217;s possible inside of a WordPress website, and kind of maintaining the job market for people who are implementing already. But hopefully that fear will go away because of all these different things.</p>\n\n\n\n<p>[00:34:32] Ryan Welcher: Yeah, I think it&#8217;s kind of like the way a lot of developers are looking at AI right now. People are terrified AI&#8217;s going to take over. It&#8217;s not, you&#8217;re just going going to have to learn to use AI to get the job done. You still need to have the skillset to tell it what you need to do, right?</p>\n\n\n\n<p>It&#8217;s the same with all this. Like, so the interactivity API, it&#8217;s really cool, and it&#8217;s ripe for someone to write a library of interactions with a UI. So the implementers who don&#8217;t maybe write that level of JavaScript, or any JavaScript, can just install that plugin. And now they can make their animations, and it&#8217;s like an animation library that&#8217;s got a UI.</p>\n\n\n\n<p>I think it&#8217;s just going to open up other opportunities for the people writing code and building plugins and things like that. I mean, I think with change, change is hard. People fear change, right? It&#8217;s figuring out what the new opportunities are.</p>\n\n\n\n<p>[00:35:16] Nathan Wrigley: Okay, let&#8217;s just talk about AI for just a minute. I really don&#8217;t want to get too much into AI because I&#8217;m coming from a real point of ignorance. But like you said, there&#8217;s a ton of information, misinformation. I don&#8217;t know what the right word is, that AI is basically going to be able to make it possible for anybody to speak a sentence and have a website. Give me a website, I want to read all about cars. And you just go off and it&#8217;ll come up with a website for that particular purpose. Is WordPress aligning itself to be useful with AI, do you think?</p>\n\n\n\n<p>[00:35:47] Ryan Welcher: Yeah, I think so. I mean, AI is the new hotness, right? And it&#8217;s getting less and less expensive to do the AI stuff, you know, the LLMs and all that stuff. And it&#8217;s getting better, and it&#8217;s only going to get better and smarter and faster. I think that there&#8217;s, again, it&#8217;s just going to change what you have to do as a developer, right?</p>\n\n\n\n<p>I am behind on AI, but I&#8217;ve made a concerted effort to start using Cursor AI, which I think is a lot of fun. I&#8217;m finding that like, I still have to be a developer to tell it what I want, right? But you can absolutely say, hey, build me a website that sells cars. And it&#8217;ll build you a website that sells cars. Who knows what the code looks like, and if you can maintain it, and if there&#8217;s a bug in there, can you find it?</p>\n\n\n\n<p>So I think there&#8217;s like, I don&#8217;t know, I&#8217;m sure there are people listening that are like, oh, you don&#8217;t know what you&#8217;re talking about. You can already do that in AI and it&#8217;s amazing. Because I&#8217;m just not, it&#8217;s like the running joke, in JavaScript it&#8217;s like, there&#8217;s a new library released every other weekend. I feel like there&#8217;s a new AI tool that&#8217;s like better and better and better like at every day.</p>\n\n\n\n<p>[00:36:37] Nathan Wrigley: I am finding it fascinating that a lot of people who are putting out content into the WordPress space, videos and things like that, they&#8217;re making a concerted effort to bind AI into WordPress. It&#8217;s not like they&#8217;ve just pivoted completely to, let&#8217;s build websites with AI. It&#8217;s more, let&#8217;s find a thing in WordPress that we can do in a heartbeat, and we actually want to do it inside of WordPress, and let&#8217;s just add a piece of AI on top of that to enable me to do this curious thing, and solve this problem that I&#8217;ve got with a client website.</p>\n\n\n\n<p>So it seems like people are using AI just to build stuff on top of WordPress, and not really the opposite. I haven&#8217;t seen any sort of move away. I don&#8217;t need WordPress anymore. That just doesn&#8217;t seem to be what I&#8217;m seeing.</p>\n\n\n\n<p>[00:37:22] Ryan Welcher: And I think it&#8217;s because the people that are doing that are, that&#8217;s where they work is in WordPress, right? Like, if you&#8217;re using, I don&#8217;t know, Wix or whatever, or like Next.js or any sort of like other platform for web stuff, I think you would see people trying to apply these AI things to that.</p>\n\n\n\n<p>I think it&#8217;s a huge opportunity for an AI to be able to create block patterns and create templates that work properly. It&#8217;s hard to do right now because I don&#8217;t think the LLMs really have the information for it. Like, it&#8217;s not because of the way that the data&#8217;s stored, it&#8217;s sort of different than, like it&#8217;s not really that well documented, maybe. I may not be making sense right now. There&#8217;s no real like example, right? Because it&#8217;s sort of different.</p>\n\n\n\n<p>[00:37:58] Nathan Wrigley: We need you to create more examples, yeah.</p>\n\n\n\n<p>[00:38:02] Ryan Welcher: I think what&#8217;s really exciting is that having to be in an, like an encyclopedia of APIs, having to like to the documentation site all the time, I think that&#8217;s going to go away. It&#8217;s already going away. Things like GitHub Copilot and these intergrated AI tools in IDEs and everything. Now you can just be like, write me a plugin that does this. Or like, what&#8217;s the parameter name that I need for WP Query to be able to do a taxonomy query, right? It&#8217;ll just tell you.</p>\n\n\n\n<p>You can just do that. Let it do its thing while you&#8217;re working on other things. And I think the days of like Stack Overflow, you know what I mean? That&#8217;s like, you Google the problem and the first example, and most upvoted answer, gets copied and pasted, right? I think that&#8217;s going to, maybe not replace, but the new Stack Overflow is like these AI tools that you can ask questions on, how do I do this? I don&#8217;t know, I think it&#8217;s just changing things.</p>\n\n\n\n<p>[00:38:45] Nathan Wrigley: I think it&#8217;s a really interesting time and it doesn&#8217;t make me feel I&#8217;m nervous. I&#8217;m more sanguine about it, in all honesty. Yeah, maybe a year ago I was kind of assuming a bit like the sky was going to fall in, but it really does appear that people who are making interesting things in the AI WordPress space are just finding curious holes, yeah. And filling them up.</p>\n\n\n\n<p>Okay, so Jamie Marsland did something the other day where he put a video together where he created a little iPhone app where he could upload images and click a button and it was able to do what Jamie wanted. And I think the same will be true, you know, for clients that will come to you. I&#8217;ve got this unique problem. Maybe that would&#8217;ve taken a week of developer time in the past. Maybe now it will be able to be done in a heartbeat, in more like an hour or a couple of hours or something like that. So it makes the possibilities for real bespoke websites much more possible.</p>\n\n\n\n<p>[00:39:33] Ryan Welcher: Yeah. And like hobbyists, kids who want to get into coding, that&#8217;s fantastic. You can just say, I want to build a website for my dog, and then all of a sudden they&#8217;re like learning by osmosis how coding works and that sort of stuff.</p>\n\n\n\n<p>The number of times that I&#8217;ve talked to a developer, and I&#8217;ve done this myself, where I&#8217;ve built a little like one-off thing, like my wife likes to track, she&#8217;s really into gut health. So like all the different like vegetables and stuff, you know, this like little point system. So I built a, just a like a really simple little app for it. It was like a weekend project. I probably could&#8217;ve done it in like half an hour in AI, and like that would&#8217;ve been nice. And it&#8217;s, you know, she doesn&#8217;t care about the features. She doesn&#8217;t care about what the code looks like. She just wants this thing that she can track information on.</p>\n\n\n\n<p>[00:40:13] Nathan Wrigley: Yeah, I think that&#8217;s going to be the curious thing. The thing that probably would&#8217;ve been a real cost benefit analysis in the past. They&#8217;re going to take, you know, something along the lines of that it would take three to six developers, six weeks to pull it off. Whereas now it&#8217;ll be, it&#8217;s going to take two developers an afternoon to pull it off. I mean, it might be that things need tidying up, but it just suddenly makes the possibilities, I don&#8217;t know, much more possible.</p>\n\n\n\n<p>[00:40:38] Ryan Welcher: For sure. Like, there&#8217;s a classic joke about like unit tests in code. Like, ain&#8217;t nobody got time for unit tests, because once you&#8217;ve written the code, you&#8217;re never going to go back and write those tests. What if you told an AI, hey, go write all my unit tests for this code base. And even if it gets some of it wrong, you&#8217;re still going to get, you know, it&#8217;s going to save a lot of time, it&#8217;s going to do a lot of that busy work for you.</p>\n\n\n\n<p>And I mean, I&#8217;ve never tested that. It would be really interesting to see, if we pointed it to like the WordPress repo, which has got, I don&#8217;t know what the percentage of test coverage is, but it just said, cover everything else in tests and see what happens. That&#8217;d be super fun. Who knows if it&#8217;d work, but yeah.</p>\n\n\n\n<p>[00:41:11] Nathan Wrigley: I think it&#8217;s a really exciting time in WordPress. I think there&#8217;s so much going on. You&#8217;ve just described a whole ton of it over the past 40 minutes or so. Yeah, it&#8217;s really, genuinely feels like there&#8217;s a lot of scope for WordPress.</p>\n\n\n\n<p>Well, whether the number goes up from 43 or stagnates kind of isn&#8217;t really what interests me. It&#8217;s more what&#8217;s possible, and the kind of crowd that you are going to be speaking to this week are the very, very audience that are going to make this stuff possible into the future.</p>\n\n\n\n<p>So good luck and thank you. And I hope that the presentation goes well, and I pray that the internet holds up for you.</p>\n\n\n\n<p>[00:41:43] Ryan Welcher: It&#8217;ll be a very one-sided, vote free presentation. So hopefully, hopefully they get it sorted out.</p>\n\n\n\n<p>[00:41:50] Nathan Wrigley: Ryan Welcher, thank you so much for spending time with me today. It was really interesting. Thank you so much.</p>\n\n\n\n<p>[00:41:55] Ryan Welcher: Thank you so much for having me.</p>\n</div>\n\n\n\n<p>On the podcast today we have <a href=\"https://www.youtube.com/c/RyanWelcherCodes\">Ryan Welcher</a>.</p>\n\n\n\n<p>Ryan is a Developer Advocate sponsored by Automattic. He focuses on removing barriers to adoption for developers working with Gutenberg and WordPress. He is a seasoned WordPress developer and regular contributor to WordPress and the Gutenberg project. He also streams on Twitch as RyanWelcherCodes where he focuses on custom block development.</p>\n\n\n\n<p>This interview was recorded at WordCamp Asia 2025 in Manila, where Ryan was giving his “Block Developer Cookbook” workshop for the second year running. Ryan spends much of his time creating documentation, running live streams, and writing articles explaining the nuts and bolts of new WordPress features for developers. He shares his journey from admiring the “platform evangelists” of the Flash era to finding his own dream job helping developers understand and implement the newest technologies in WordPress.</p>\n\n\n\n<p>We talk about some of the biggest recent updates to WordPress Core, including the Block Bindings API, Plugin Template Registration API, Preview Options API, and the new Data Views. Ryan breaks down what these new tools are, why they matter, and how they’re making WordPress block development both more powerful and more accessible.</p>\n\n\n\n<p>He also discusses the growing emphasis on intentional, high-quality documentation and resources over the past few years, and how many teams are working to make life easier for developers of all skill levels.</p>\n\n\n\n<p>We chat about the balance between the increasing flexibility of WordPress’s UI and the risk of overwhelming new users, as well as exploring how emerging technologies like AI are shaping the future for WordPress developers and hobbyists alike.</p>\n\n\n\n<p>If you’re interested in what’s new in WordPress development, want to understand where the project is heading, or are curious about the real impact of recent changes and features, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p>Ryan&#8217;s session at WordCamp Asia: <a href=\"https://asia.wordcamp.org/2025/session/the-block-developer-cookbook-wc-asia-2025-edition/\">The Block Developer Cookbook: WC Asia 2025 Edition</a></p>\n\n\n\n<p><a href=\"https://developer.wordpress.org/block-editor/reference-guides/block-api/block-bindings/\">Block Bindings API</a></p>\n\n\n\n<p><a href=\"https://developer.wordpress.org/block-editor/reference-guides/interactivity-api/\">Interactivity API</a></p>\n\n\n\n<p><a href=\"https://developer.wordpress.org/news/\">WordPress Developer News</a></p>\n\n\n\n<p><a href=\"https://learn.wordpress.org/\">Learn WordPress</a></p>\n\n\n\n<p><a href=\"https://developer.wordpress.org/block-editor/\">Block Editor Handbook</a></p>\n\n\n\n<p><a href=\"https://www.twitch.tv/ryanwelchercodes\">RyanWelcherCodes</a> on Twitch</p>\n\n\n\n<p><a href=\"https://www.youtube.com/c/RyanWelcherCodes\">RyanWelcherCodes</a> on YouTube</p>\n\n\n\n<p><a href=\"https://make.wordpress.org/\">Make WordPress</a></p>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/\">Make WordPress Core</a></p>\n\n\n\n<p><a href=\"https://github.com/WordPress/gutenberg\">Gutenberg on GitHub</a></p>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/2024/10/20/new-plugin-template-registration-api-in-wordpress-6-7/\">Plugin Template Registration API</a></p>\n\n\n\n<p><a href=\"https://developer.wordpress.org/plugins/settings/options-api/\">Preview Options API</a></p>\n\n\n\n<p><a href=\"https://www.cursor.com/\">Cursor AI</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 23 Apr 2025 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:49;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"Do The Woo Community: Breaking Language Barriers: The Journey of Translating WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"https://dothewoo.io/?post_type=blog&p=94712\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:89:\"https://dothewoo.io/blog/breaking-language-barriers-the-journey-of-translating-wordpress/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:226:\"The web connects diverse communities, yet language barriers persist. Open source translations enhance accessibility in platforms like WordPress, fostering collaboration and empowering users to create in their native languages.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 23 Apr 2025 13:13:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:9:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Wed, 14 May 2025 04:57:20 GMT\";s:12:\"content-type\";s:8:\"text/xml\";s:13:\"last-modified\";s:29:\"Wed, 14 May 2025 04:45:29 GMT\";s:4:\"vary\";s:15:\"Accept-Encoding\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:4:\"gzip\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 1\";}}s:5:\"build\";i:1743984985;s:21:\"cache_expiration_time\";i:1747241840;s:23:\"__cache_expiration_time\";i:1747241840;}', 'off');
