(68, 1, '2025-05-14 05:47:55', '2025-05-14 05:47:55', '<h2>Add Your Heading Text Here</h2>				\n		<p>Lorem ipsum dolor sit amet, consectetur adipiscing elit. Ut elit tellus, luctus nec ullamcorper mattis, pulvinar dapibus leo.</p>		\n			<iframe loading=\"lazy\"\n					src=\"https://maps.google.com/maps?q=London%20Eye%2C%20London%2C%20United%20Kingdom&#038;t=m&#038;z=10&#038;output=embed&#038;iwloc=near\"\n					title=\"London Eye, London, United Kingdom\"\n					aria-label=\"London Eye, London, United Kingdom\"\n			></iframe>\n										Slide 1 HeadingLorem ipsum dolor sit amet consectetur adipiscing elit dolorClick HereSlide 2 HeadingLorem ipsum dolor sit amet consectetur adipiscing elit dolorClick HereSlide 3 HeadingLorem ipsum dolor sit amet consectetur adipiscing elit dolorClick Here				\n														Previous slide\n														Next slide\n							<h3>\n					This page is\n					Amazing\n				</h3>', 'Homepage', '', 'inherit', 'closed', 'closed', '', '19-autosave-v1', '', '', '2025-05-14 05:56:33', '2025-05-14 05:56:33', '', 19, 'http://localhost/wordpress/?p=68', 0, 'revision', '', 0);

